import { Component, OnInit, isDevMode, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Invoice } from '../../models/invoice';
import { InvoiceCalcService, InvoiceTotals } from '../../services/invoice-calc.service';
import { InvoiceStoreService } from '../../services/invoice-store.service';
import { ElectronService } from '../../services/electron.service';

type InvoiceTotalsWithExtras = InvoiceTotals & {
  fodec: number;
  timbre: number;
  totalTTCFinal: number;
};

@Component({
  selector: 'app-invoice-preview',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './invoice-preview.component.html',
  styleUrls: ['./invoice-preview.component.css']
})
export class InvoicePreviewComponent implements OnInit {
  invoice: Invoice | null = null;

  // Totaux de base (HT/TVA/TTC) calculés par ton service
  totals: InvoiceTotals = {
    totalHT: 0,
    totalTVA: 0,
    totalTTC: 0,
    remise: 0,
    totalHTApresRemise: 0,
    totalTVAApresRemise: 0
  };

  // ✅ Totaux finaux avec FODEC + TIMBRE
  totalsFinal: InvoiceTotalsWithExtras = {
    ...this.totals,
    fodec: 0,
    timbre: 1.0,
    totalTTCFinal: 0
  };

  logoAvailable = true;

  readonly isDev = isDevMode();
  debugUrl = '';
  debugId = '';
  debugCount = 0;
  marker = 'PREVIEW_COMPONENT_FINAL_' + Math.random().toString(16).slice(2);

  // constantes
  readonly FODEC_RATE = 0.01; // 1%
  readonly TIMBRE = 1.0;      // 1,000 DT

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private store: InvoiceStoreService,
    public calc: InvoiceCalcService,
    public electron: ElectronService,
    private cdr: ChangeDetectorRef
  ) {}

  async ngOnInit(): Promise<void> {
    // debug visible tout de suite
    this.debugUrl =
      (window.location.href || window.location.pathname || window.location.hash || '(no-url)') + '';
    this.debugId = '(loading...)';
    this.debugCount = -1;
    this.cdr.detectChanges();

    await this.store.load();

    let id =
      this.route.snapshot.queryParamMap.get('id') ??
      this.route.snapshot.paramMap.get('id') ??
      this.route.snapshot.paramMap.get('invoiceId') ??
      '';

    // fallback depuis URL
    const href = window.location.href || '';
    if (!id && href) {
      const m1 = href.match(/\/invoices\/([^\/?#]+)\/preview/i);
      if (m1?.[1]) id = m1[1];

      if (!id) {
        const m2 = href.match(/[?&]id=([^&]+)/i);
        if (m2?.[1]) id = decodeURIComponent(m2[1]);
      }
    }

    this.debugId = id || '(no-id)';
    this.debugCount = this.store.getSnapshot().length;

    if (this.isDev) {
      console.log('[InvoicePreview] LOADED', this.marker, {
        href,
        routerUrl: this.router.url,
        id: this.debugId,
        count: this.debugCount
      });
    }

    this.cdr.detectChanges();

    if (!id) {
      this.invoice = null;
      this.cdr.detectChanges();
      return;
    }

    const inv = await this.store.getById(id);
    this.invoice = inv;

    if (inv) {
      this.totals = this.calc.totals(inv);
      this.computeFinalTotals();
    } else if (this.isDev) {
      console.warn('[InvoicePreview] invoice NOT FOUND for id:', id);
    }

    this.cdr.detectChanges();
  }

  private computeFinalTotals(): void {
    // On prend HT après remise si ton calc le fournit, sinon totalHT
    const baseHT = Number(this.totals.totalHTApresRemise || this.totals.totalHT || 0);
    const baseTVA = Number(this.totals.totalTVAApresRemise || this.totals.totalTVA || 0);

    const fodec = this.round3(baseHT * this.FODEC_RATE); // 1% HT
    const timbre = this.TIMBRE;

    const totalTTCFinal = this.round3(baseHT + baseTVA + fodec + timbre);

    this.totalsFinal = {
      ...this.totals,
      fodec,
      timbre,
      totalTTCFinal
    };
  }

  private round3(n: number): number {
    return Math.round((n + Number.EPSILON) * 1000) / 1000;
  }

  back(): void {
    this.router.navigate(['/invoices']);
  }

  edit(): void {
    if (!this.invoice) return;
    this.router.navigate(['/invoices', this.invoice.id, 'edit']);
  }

  print(): void {
    window.print();
  }

  async exportPdf(): Promise<void> {
    if (!this.invoice) return;
    if (!this.electron.isElectron) return;

    try {
      const anyElectron: any = this.electron as any;

      if (typeof anyElectron.exportPdf === 'function') {
        await anyElectron.exportPdf();
        return;
      }

      if (anyElectron.ipcRenderer?.invoke) {
        await anyElectron.ipcRenderer.invoke('export-pdf');
        return;
      }

      alert('Export PDF non configuré dans ElectronService.');
    } catch (e) {
      console.error(e);
      alert('Erreur export PDF. Voir console.');
    }
  }

  // ✅ TTC en lettres basé sur total final
  totalTtcInWords(amount: number): string {
    const dinars = Math.floor(amount);
    const millimes = Math.round((amount - dinars) * 1000);

    const dinarsWords = this.frNumberToWords(dinars);
    const millimesWords = this.frNumberToWords(millimes);

    if (millimes > 0) {
      return `${dinarsWords} dinars et ${millimesWords} millimes`;
    }
    return `${dinarsWords} dinars`;
  }

  // convertisseur FR basique (0..999999)
  private frNumberToWords(n: number): string {
    const units = [
      'zéro','un','deux','trois','quatre','cinq','six','sept','huit','neuf',
      'dix','onze','douze','treize','quatorze','quinze','seize',
      'dix-sept','dix-huit','dix-neuf'
    ];
    const tens = ['', '', 'vingt','trente','quarante','cinquante','soixante','soixante','quatre-vingt','quatre-vingt'];

    const under100 = (x: number): string => {
      if (x < 20) return units[x];
      const t = Math.floor(x / 10);
      const u = x % 10;
      if (t === 7) return `soixante-${under100(10 + u)}`;
      if (t === 9) return `quatre-vingt-${under100(10 + u)}`;
      if (t === 8 && u === 0) return 'quatre-vingts';
      if (u === 1 && (t === 2 || t === 3 || t === 4 || t === 5 || t === 6)) return `${tens[t]} et un`;
      return u ? `${tens[t]}-${units[u]}` : tens[t];
    };

    const under1000 = (x: number): string => {
      if (x < 100) return under100(x);
      const h = Math.floor(x / 100);
      const r = x % 100;
      const head = h === 1 ? 'cent' : `${units[h]} cent${r === 0 ? 's' : ''}`;
      return r ? `${head} ${under100(r)}` : head;
    };

    if (n < 1000) return under1000(n);

    const thousands = Math.floor(n / 1000);
    const rest = n % 1000;

    const th = thousands === 1 ? 'mille' : `${under1000(thousands)} mille`;
    return rest ? `${th} ${under1000(rest)}` : th;
  }
}
