<div class="preview-toolbar no-print">
  <button class="btn ghost" (click)="back()">Retour</button>
  <div class="toolbar-actions">
    <button class="btn outline" (click)="edit()" [disabled]="!invoice">Modifier</button>
    <button class="btn primary" (click)="print()" [disabled]="!invoice">Imprimer</button>
    <button class="btn ghost" *ngIf="electron.isElectron" (click)="exportPdf()" [disabled]="!invoice">
      Exporter PDF
    </button>
  </div>
</div>

<div class="paper" *ngIf="invoice as inv">

  <!-- HEADER (3 colonnes) -->
  <div class="top-header">
    <div class="top-left">
      <div class="societe-title">SOCIETE PRATIQUES ALUMINIUM</div>
      <div class="small">
        59, Av. de l’Indépendance - Cité Ettadhamen<br />
        2041 ARIANA
      </div>
    </div>

    <div class="top-center">
      <img
        class="logo"
        *ngIf="logoAvailable"
        src="assets/logospa.png"
        alt="SPA"
        (error)="logoAvailable = false"
      />
      <div class="logo-fallback" *ngIf="!logoAvailable">SPA</div>
    </div>

    <div class="top-right small ar">
      شركة تطبيقات الألومنيوم<br />
      59، شارع الاستقلال - حي التضامن<br />
      2041 أريانة
    </div>
  </div>

  <!-- CLIENT BLOCK CENTER (juste sous le logo) -->
  <div class="client-center-block">
    <div class="client-name">{{ inv.client.nom }}</div>
    <div class="small">
      {{ inv.client.adresse }}<br />
      <span *ngIf="inv.client.mf">CODE T.V.A : {{ inv.client.mf }}</span>
    </div>
  </div>

  <!-- DATE RIGHT -->
  <div class="date-right small">
    Tunis, le {{ inv.date | date:'dd/MM/yyyy' }}
  </div>

  <!-- TITLE -->
  <div class="invoice-title">
    FACTURE N° <span class="mono">{{ inv.numero }}</span>
  </div>

  <div class="small bc">
    Bon de Commande N° <span class="mono">{{ inv.conditions || '—' }}</span>
  </div>

  <!-- TABLE LIGNES (exactement le nombre de produits) -->
  <table class="lines">
    <thead>
      <tr>
        <th class="w-ord">ORD</th>
        <th>DESIGNATIONS</th>
        <th class="w-u">U</th>
        <th class="w-q">QUANT</th>
        <th class="w-pu">P.UNIT</th>
        <th class="w-pt">P.TOTAL</th>
      </tr>
    </thead>

    <tbody>
      <tr *ngFor="let line of inv.lignes; let i = index">
        <td class="center">{{ i + 1 }}</td>
        <td>{{ line.designation }}</td>
        <td class="center">{{ line.unite }}</td>
        <td class="num">{{ line.quantite | number:'1.0-2' }}</td>
        <td class="num">{{ line.prixUnitaire | number:'1.3-3' }}</td>
        <td class="num">{{ calc.lineHT(line) | number:'1.3-3' }}</td>
      </tr>
    </tbody>
  </table>

  <!-- TOTALS BLOCK (droite) -->
  <div class="totals-area">
    <table class="totals">
      <tbody>
        <tr>
          <td>TOTAL Hors taxes</td>
          <td class="num">{{ totals.totalHT | number:'1.3-3' }}</td>
        </tr>

        <tr *ngIf="totals.remise > 0">
          <td>Remise</td>
          <td class="num">- {{ totals.remise | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>Fodec (1%)</td>
          <td class="num">{{ totalsFinal.fodec | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>TOTAL Hors T.V.A</td>
          <td class="num">{{ totals.totalHT | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>T.V.A (19%)</td>
          <td class="num">{{ totals.totalTVA | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>Timbre</td>
          <td class="num">{{ totalsFinal.timbre | number:'1.3-3' }}</td>
        </tr>

        <tr class="grand">
          <td>TOTAL T.T.C</td>
          <td class="num">{{ totalsFinal.totalTTCFinal | number:'1.3-3' }}</td>
        </tr>
      </tbody>
    </table>
  </div>

  <!-- TTC EN LETTRES -->
  <div class="amount-words">
    Arrêtée la présente facture à la somme de :
    <span class="words">{{ totalTtcInWords(totalsFinal.totalTTCFinal) }}</span> TTC.
  </div>

  <!-- SIGNATURE -->
  <div class="sign-row">
    <div></div>
    <div class="signature-zone">
      <div class="signature-line"></div>
    </div>
  </div>

  <!-- FOOTER -->
  <div class="footer">
    R.C. : B035 145 2004 - M.F. : 89 83 00 WIA/M/000 - RIB : 25079 0000000 213 555 60
    zitouna Mutuelle ville<br />
    Tél. : 71 515 491 - Fax : 70 661 034 - E-mail : saadani.karim@planett.tn
  </div>
</div>

<div class="empty card" *ngIf="!invoice">
  Facture introuvable.
</div>
